"use strict";(self.webpackChunkalgorithms_way23_ru=self.webpackChunkalgorithms_way23_ru||[]).push([[918],{1482:(e,a,n)=>{n.r(a),n.d(a,{data:()=>d});const d=JSON.parse('{"key":"v-7e3ce524","path":"/pandoc-basic.html","title":"Основы Pandoc","lang":"ru-RU","frontmatter":{"title":"Основы Pandoc","date":"2020-12-18","categories":["Программы"],"tags":["pandoc"]},"excerpt":"","headers":[{"level":2,"title":"Конвертация","slug":"конвертация","link":"#конвертация","children":[]},{"level":2,"title":"Форматы файлов","slug":"форматы-фаилов","link":"#форматы-фаилов","children":[]},{"level":2,"title":"Части документов и полноценный документ","slug":"части-документов-и-полноценныи-документ","link":"#части-документов-и-полноценныи-документ","children":[]},{"level":2,"title":"Кодировка","slug":"кодировка","link":"#кодировка","children":[]},{"level":2,"title":"Ссылки","slug":"ссылки","link":"#ссылки","children":[]}],"git":{"updatedTime":1669020793000},"filePathRelative":"pandoc-basic.md"}')},9752:(e,a,n)=>{n.r(a),n.d(a,{default:()=>p});var d=n(6252),s=n(3577);const r={id:"frontmatter-title",tabindex:"-1"},i=(0,d._)("a",{class:"header-anchor",href:"#frontmatter-title","aria-hidden":"true"},"#",-1),l={href:"https://pandoc.org",target:"_blank",rel:"noopener noreferrer"},t=(0,d.uE)('<h2 id="конвертация" tabindex="-1"><a class="header-anchor" href="#конвертация" aria-hidden="true">#</a> Конвертация</h2><p>Pandoc — консольное приложение и поддерживает стандартный синтаксис параметров.</p><p>По умолчанию Pandoc принимает данные для конвертации из входного потока и отправляет во выходной поток. Чтобы брать исходные данные из файла передайте ему имя файла:</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>pandoc input01.md\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Чтобы указать файл для вывода используйте параметр <code>-o</code>:</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>pandoc <span class="token parameter variable">-o</span> output.html input01.md\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>На вход можно передать несколько файлов, в этом случае Pandoc объединит их в один:</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>pandoc <span class="token parameter variable">-o</span> output.html input01.md input02.md\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="форматы-фаилов" tabindex="-1"><a class="header-anchor" href="#форматы-фаилов" aria-hidden="true">#</a> Форматы файлов</h2><p>В предыдущих примерах Pandoc автоматически определял формат файла по расширению. Команды <code>-f</code> (<code>--from</code>) и <code>-t</code> (<code>--to</code>) указывают формат явно:</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>pandoc <span class="token parameter variable">-o</span> output.txt <span class="token parameter variable">-f</span> markdown <span class="token parameter variable">-t</span> dokuwiki input01.md input02.md\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Списки поддерживаемых входных и выходных форматов выводятся командами:</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>pandoc --list-input-formats\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>pandoc --list-output-formats\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="части-документов-и-полноценныи-документ" tabindex="-1"><a class="header-anchor" href="#части-документов-и-полноценныи-документ" aria-hidden="true">#</a> Части документов и полноценный документ</h2><p>По умолчанию, Pandoc выводит только преобразованные в целевой формат фрагменты. Если нужно получить полноценный файл в целевом формате, то укажите параметр <code>-s</code> (<code>--standalone</code>) .</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>pandoc <span class="token parameter variable">-o</span> output.html <span class="token parameter variable">-f</span> markdown <span class="token parameter variable">-t</span> html <span class="token parameter variable">-s</span> input01.md input02.md\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Для формата <code>HTML</code> полноценный документ будет включать в себя все обязательные для документа теги <code>head</code>, <code>body</code> и остальные, а если конвертировать фрагменты то в выходном файле будут только отдельные абзацы.</p><h2 id="кодировка" tabindex="-1"><a class="header-anchor" href="#кодировка" aria-hidden="true">#</a> Кодировка</h2><p>Pandoc использует кодировку <code>utf-8</code> для выходных и выходных файлов.</p><h2 id="ссылки" tabindex="-1"><a class="header-anchor" href="#ссылки" aria-hidden="true">#</a> Ссылки</h2>',21),c={href:"https://pandoc.org/MANUAL.html",target:"_blank",rel:"noopener noreferrer"},o={},p=(0,n(3744).Z)(o,[["render",function(e,a){const n=(0,d.up)("ExternalLinkIcon");return(0,d.wg)(),(0,d.iD)("div",null,[(0,d._)("h1",r,[i,(0,d.Uk)(" "+(0,s.zw)(e.$frontmatter.title),1)]),(0,d._)("p",null,[(0,d._)("a",l,[(0,d.Uk)("Pandoc"),(0,d.Wm)(n)]),(0,d.Uk)(" конвертирует текстовые файлы из одних форматов в другие. Рассмотрим его базовые команды.")]),t,(0,d._)("ul",null,[(0,d._)("li",null,[(0,d._)("a",c,[(0,d.Uk)("Pandoc Manual"),(0,d.Wm)(n)])])])])}]])}}]);